def check_connection(available_symbols=None):
    if mt5.account_info() is None:
        log.warning("Conexion perdida - reconectando...")
        ok = connect()
        if ok and available_symbols:
            for sym in available_symbols:
                mt5.symbol_select(sym, True)
            _costos_cache.clear()  # forzar recalculo
        return ok
    return True

